<?php require __DIR__.'/../includes/bootstrap.php';require_auth();if(!booths_schema_ready())redirect('upgrade-booths-marketplace.php');$u=user();$s=db()->prepare("SELECT b.*,(SELECT COUNT(*) FROM booth_products p WHERE p.booth_id=b.id) products,(SELECT COUNT(*) FROM booth_orders o WHERE o.booth_id=b.id) orders FROM booths b WHERE b.owner_user_id=? OR ?='admin' ORDER BY b.created_at DESC");$s->execute([$u['id'],$u['role']]);$booths=$s->fetchAll();app_header('My Booths');?>
<section class="dashboard-hero"><p class="eyebrow">EXHIBITOR CONTROL ROOM</p><h1>My Booths</h1><p><a class="button primary" href="create.php">Open Another Booth</a> <a class="button ghost" href="index.php">Visit Exhibit Hall</a></p></section><section class="dashboard-grid"><?php foreach($booths as $b):?><article class="app-card"><span class="status-badge <?=e($b['status'])?>"><?=e(ucfirst($b['status']))?></span><h2><?=e($b['name'])?></h2><p><?=$b['products']?> products · <?=$b['orders']?> orders</p><p><a class="button primary" href="manage.php?id=<?=$b['id']?>">Manage Booth</a><?php if($b['status']==='approved'):?> <a class="button ghost" href="view.php?slug=<?=urlencode($b['slug'])?>">View Public Booth</a><?php endif?></p></article><?php endforeach?><?php if(!$booths):?><article class="app-card"><h2>No booth yet</h2><p>Open a booth to join the virtual exhibit hall.</p></article><?php endif?></section><?php app_footer();